import React from 'react';
import {
  Bar,
  BarChart,
  CartesianGrid,
  Legend,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import { formatNumber, formatVnd } from '../../../utils/formatters';
import reportStyles from '../../../styles/erpReportPage.module.css';
import { AnalyticsReportShell } from '../../../components/report';

const TEST_ID = 'erp-tong-quan-tai-chinh';
const PAGE_ID = 'tong-quan-tai-chinh';

const kpiCards = [
  { key: 'revenue', title: 'Doanh thu T5/2026', value: 4850000000, change: 12.4 },
  { key: 'orders', title: 'Đơn hàng đang SX', value: 47, change: 8.1 },
  { key: 'employees', title: 'Nhân viên', value: 312, change: -2.3 },
  { key: 'stock', title: 'Giá trị tồn kho', value: 12340000000, change: 5.7 },
];

const chartData = [
  { month: 'T1', revenue: 2980000000, cogs: 2210000000 },
  { month: 'T2', revenue: 3450000000, cogs: 2580000000 },
  { month: 'T3', revenue: 4100000000, cogs: 3020000000 },
  { month: 'T4', revenue: 4320000000, cogs: 3180000000 },
  { month: 'T5', revenue: 4850000000, cogs: 3530000000 },
];

const DashboardPage: React.FC = () => (
  <AnalyticsReportShell
    testId={TEST_ID}
    pageId={PAGE_ID}
    title="Tổng quan tài chính"
    titleIconClass="fas fa-tachometer-alt"
    listTitle="Tổng quan tài chính"
    loading={false}
    hasData
    suppressEmptyGate
    filterItems={[]}
    showViewButton={false}
    onLoad={() => {}}
    emptyMessage=""
  >
    <p className={reportStyles.subtitle} style={{ margin: '0 0 12px' }}>
      Số liệu tài chính tổng hợp (mô phỏng — sẽ nối API sau)
    </p>
    <div className={reportStyles.kpiGrid}>
      {kpiCards.map(k => (
        <div key={k.key} className={reportStyles.kpiCard}>
          <div className={reportStyles.kpiLabel}>{k.title}</div>
          <div className={reportStyles.kpiValue}>
            {k.key === 'orders' || k.key === 'employees'
              ? formatNumber(k.value)
              : formatVnd(k.value)}
          </div>
          <div className={reportStyles.subtitle}>
            {k.change > 0 ? '+' : ''}
            {k.change}% so với kỳ trước
          </div>
        </div>
      ))}
    </div>
    <div className={reportStyles.chartCard}>
      <ResponsiveContainer width="100%" height={300}>
        <BarChart data={chartData}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="month" />
          <YAxis tickFormatter={v => `${(Number(v) / 1e9).toFixed(1)}B`} />
          <Tooltip formatter={(v: number) => formatVnd(v)} />
          <Legend />
          <Bar dataKey="revenue" name="Doanh thu" fill="#1677ff" />
          <Bar dataKey="cogs" name="Giá vốn" fill="#fa8c16" />
        </BarChart>
      </ResponsiveContainer>
    </div>
  </AnalyticsReportShell>
);

export default DashboardPage;
